export type Event = 
  | { type: 'Deposited'; amount: number; timestamp: Date }
  | { type: 'Withdrew'; amount: number; timestamp: Date }
  | { type: 'Transferred'; amount: number; to: string; timestamp: Date }
  | { type: 'TransferReceived'; amount: number; from: string; timestamp: Date }
  | { type: 'AccountCreated'; accountId: string; timestamp: Date }

export class Account {
  private events: Event[] = []
  private balance: number = 0

  constructor(private accountId: string) {}

  deposit(amount: number): void {
    if (amount <= 0) throw new Error('Deposit amount must be positive')
    const event: Event = {
      type: 'Deposited',
      amount,
      timestamp: new Date()
    }
    this.events.push(event)
    this.balance += amount
  }

  withdraw(amount: number): void {
    if (amount <= 0) throw new Error('Withdrawal amount must be positive')
    if (this.balance < amount) throw new Error('Insufficient funds')
    const event: Event = {
      type: 'Withdrew',
      amount,
      timestamp: new Date()
    }
    this.events.push(event)
    this.balance -= amount
  }

  transfer(amount: number, to: string): void {
    if (amount <= 0) throw new Error('Transfer amount must be positive')
    if (this.balance < amount) throw new Error('Insufficient funds for transfer')
    const event: Event = {
      type: 'Transferred',
      amount,
      to,
      timestamp: new Date()
    }
    this.events.push(event)
    this.balance -= amount
  }
```

The deposit method adds a Deposited event and increases the balance. The withdraw method validates sufficient funds exist before creating a Withdrew event and reducing the balance. The transfer method similarly validates funds and records a Transferred event with the recipient account ID.

